// // This module implements a 9-bit shift register that shifts right on every negative clock edge and loads an 8-bit input value when the load signal is low.
module top_module (
	input clk,
	input load,
	input [7:0] data,
	output reg [7:0] q);always @(posedge clk) begin
		if (load)
			q <= data;
		else
			q <= q << 1;
	end

endmodule
